using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change #1: Default discriminator property renamed from "Discriminator" to "$type".
            // Existing documents use "Discriminator", so preserve it.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change #2: Id values no longer include the discriminator prefix.
            // Existing documents use "Blog|1" format, so opt back in.
            b.HasDiscriminatorInJsonId();
        });

        // Breaking change #3: HasIndex now throws for Cosmos (was silently ignored in 8.0).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

